if (! function_exists('data_to_emoji_art')) {
    function data_to_emoji_art($values, $max_bar_width = null, $fill_emoji = null, $empty_emoji = null, $label_width = null, $show_values = null)
    {
        if (empty($values)) { return json_encode(['error' => 'No values provided']); }

        $max_bar_width = $max_bar_width ?? 10;
        $fill_emoji = $fill_emoji ?? '🟦';
        $empty_emoji = $empty_emoji ?? '⬜';
        $label_width = $label_width ?? 0;
        $show_values = $show_values ?? false;

        $min = min($values);
        $max = max($values);
        $range = ($max - $min > 0) ? $max - $min : 1;

        $rows = [];
        foreach ($values as $i => $val) {
            $proportion = ($val - $min) / $range;
            $filled_count = (int)round($proportion * $max_bar_width);
            $filled_count = max(0, min($max_bar_width, $filled_count));
            $empty_count = $max_bar_width - $filled_count;
            
            $bar = str_repeat($fill_emoji, $filled_count) . str_repeat($empty_emoji, $empty_count);
            
            $label = '';
            if ($label_width > 0) {
                $label = str_pad((string)$i, $label_width);
            }
            
            $value_suffix = $show_values ? " $val" : '';
            
            $rows[] = [$label . $bar . $value_suffix];
        }

        return json_encode([
            'ok' => true,
            'rows' => $rows,
            'grid' => $rows,
            'metadata' => [
                'min' => $min,
                'max' => $max,
                'count' => count($values),
                'next_step' => "Pass the 'grid' to emoji_art_renderer to render the visual chart."
            ]
        ]);
    }
